import {{ Injectable }} from '@nestjs/common';
import {{ JobService }} from './models/job.model';
import {{ JobServiceRepository }} from './repositories/job.repository';

@Injectable()
export class JobServiceService {{
  constructor(
    private readonly repository: JobServiceRepository,
  ) {{}}

  async findAll(): Promise<JobService[]> {{
    return this.repository.findAll();
  }}

  async findById(id: string): Promise<JobService | null> {{
    return this.repository.findById(id);
  }}

  async create(data: Partial<JobService>): Promise<JobService> {{
    return this.repository.create(data);
  }}

  async update(id: string, data: Partial<JobService>): Promise<JobService> {{
    return this.repository.update(id, data);
  }}
}}
